1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: Maps a number of I2C devices on an I2C bus onto an AXI Bus.
5	-------------------------------------------------------------------------------
6	-- This file is part of 'SLAC Firmware Standard Library'.
7	-- It is subject to the license terms in the LICENSE.txt file found in the
8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_arith.all;
18	use ieee.std_logic_unsigned.all;
19	
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiLitePkg.all;
24	use surf.I2cPkg.all;
25	
26	entity I2cRegMasterAxiBridge is
27	
28	   generic (
29	      TPD_G        : time               := 1 ns;
30	      DEVICE_MAP_G : I2cAxiLiteDevArray := I2C_AXIL_DEV_ARRAY_DEFAULT_C);
31	   port (
32	      axiClk : in sl;
33	      axiRst : in sl;
34	
35	      axiReadMaster  : in  AxiLiteReadMasterType;
36	      axiReadSlave   : out AxiLiteReadSlaveType;
37	      axiWriteMaster : in  AxiLiteWriteMasterType;
38	      axiWriteSlave  : out AxiLiteWriteSlaveType;
39	
40	      i2cSelectOut    : out slv(DEVICE_MAP_G'length-1 downto 0);
41	      i2cRegMasterIn  : out I2cRegMasterInType;
42	      i2cRegMasterOut : in  I2cRegMasterOutType);
43	
44	end entity I2cRegMasterAxiBridge;
45	
46	architecture rtl of I2cRegMasterAxiBridge is
47	
48	   constant READ_C  : boolean := false;
49	   constant WRITE_C : boolean := true;
50	
51	   constant DEVICE_MAP_LENGTH_C : natural := DEVICE_MAP_G'length;
52	
53	   -- Number of device register space address bits maped into axi bus is determined by
54	   -- the maximum address size of all the devices.
55	   constant I2C_REG_ADDR_SIZE_C : natural := maxAddrSize(DEVICE_MAP_G);
56	
57	   constant I2C_REG_AXI_ADDR_LOW_C  : natural := 2;
58	   constant I2C_REG_AXI_ADDR_HIGH_C : natural :=
59	      ite(I2C_REG_ADDR_SIZE_C = 0,
60	          2,
61	          I2C_REG_AXI_ADDR_LOW_C + I2C_REG_ADDR_SIZE_C-1);
62	
63	   subtype I2C_REG_AXI_ADDR_RANGE_C is natural range
64	      I2C_REG_AXI_ADDR_HIGH_C downto I2C_REG_AXI_ADDR_LOW_C;
65	
66	   -- Number of device address bits mapped into axi bus space is determined by number of devices
67	   constant I2C_DEV_AXI_ADDR_LOW_C : natural := I2C_REG_AXI_ADDR_HIGH_C + 1;
68	   constant I2C_DEV_AXI_ADDR_HIGH_C : natural := ite(
69	      (DEVICE_MAP_LENGTH_C = 1),
70	      I2C_DEV_AXI_ADDR_LOW_C,
71	      (I2C_DEV_AXI_ADDR_LOW_C + log2(DEVICE_MAP_LENGTH_C) - 1));
72	
73	   subtype I2C_DEV_AXI_ADDR_RANGE_C is natural range
74	      I2C_DEV_AXI_ADDR_HIGH_C downto I2C_DEV_AXI_ADDR_LOW_C;
75	
76	   type RegType is record
77	      axiReadSlave   : AxiLiteReadSlaveType;
78	      axiWriteSlave  : AxiLiteWriteSlaveType;
79	      i2cSelectOut   : slv(DEVICE_MAP_G'length-1 downto 0);
80	      i2cRegMasterIn : I2cRegMasterInType;
81	   end record RegType;
82	
83	   constant REG_INIT_C : RegType := (
84	      axiReadSlave   => AXI_LITE_READ_SLAVE_INIT_C,
85	      axiWriteSlave  => AXI_LITE_WRITE_SLAVE_INIT_C,
86	      i2cSelectOut   => (others => '0'),
87	      i2cRegMasterIn => I2C_REG_MASTER_IN_INIT_C);
88	
89	   signal r   : RegType := REG_INIT_C;
90	   signal rin : RegType;
91	
92	begin
93	
94	   -------------------------------------------------------------------------------------------------
95	   -- Main Comb Process
96	   -------------------------------------------------------------------------------------------------
97	   comb : process (axiReadMaster, axiRst, axiWriteMaster, i2cRegMasterOut, r) is
98	      variable v         : RegType;
99	      variable devInt    : integer;
100	      variable axiStatus : AxiLiteStatusType;
101	      variable axiResp   : slv(1 downto 0);
102	
103	      impure function setI2cRegMaster (i : integer; readN : boolean) return I2cRegMasterInType is
104	         variable ret : I2cRegMasterInType := I2C_REG_MASTER_IN_INIT_C;
105	      begin
106	         ret.i2cAddr := DEVICE_MAP_G(i).i2cAddress;
107	         ret.tenbit  := DEVICE_MAP_G(i).i2cTenbit;
108	
109	         if (readN = READ_C) then
110	            ret.regAddr(I2C_REG_ADDR_SIZE_C-1 downto 0) := axiReadMaster.araddr(I2C_REG_AXI_ADDR_RANGE_C);
111	         else
112	            ret.regAddr(I2C_REG_ADDR_SIZE_C-1 downto 0) := axiWriteMaster.awaddr(I2C_REG_AXI_ADDR_RANGE_C);
113	         end if;
114	
115	         ret.regWrData(DEVICE_MAP_G(i).dataSize-1 downto 0) := axiWriteMaster.wData(DEVICE_MAP_G(i).dataSize-1 downto 0);
116	
117	         ret.regAddrSize := toSlv(wordCount(DEVICE_MAP_G(i).addrSize, 8) - 1, 2);
118	         ret.regAddrSkip := toSl(DEVICE_MAP_G(i).addrSize = 0);
119	         ret.regDataSize := toSlv(wordCount(DEVICE_MAP_G(i).dataSize, 8) - 1, 2);
120	         ret.endianness  := DEVICE_MAP_G(i).endianness;
121	         ret.repeatStart := DEVICE_MAP_G(i).repeatStart;
122	         return ret;
123	      end function;
124	
125	   begin
126	      v := r;
127	
128	      axiSlaveWaitTxn(axiWriteMaster, axiReadMaster, v.axiWriteSlave, v.axiReadSlave, axiStatus);
129	
130	      if (axiStatus.writeEnable = '1') then
131	
132	         -- I2C Address Space
133	         -- Decode i2c device address and send command to I2cRegMaster
134	         devInt := conv_integer(axiWriteMaster.awaddr(I2C_DEV_AXI_ADDR_RANGE_C));
135	
136	         v.i2cRegMasterIn        := setI2cRegMaster(devInt, WRITE_C);
137	         v.i2cRegMasterIn.regOp  := '1';  -- Write
138	         v.i2cRegMasterIn.regReq := '1';
139	         v.i2cSelectOut(devInt)  := '1';
140	
141	      elsif (axiStatus.readEnable = '1') then
142	         -- I2C Address Space
143	         -- Decode i2c device address and send command to I2cRegMaster
144	         devInt := conv_integer(axiReadMaster.araddr(I2C_DEV_AXI_ADDR_RANGE_C));
145	
146	         -- Send transaction to I2cRegMaster
147	         v.i2cRegMasterIn        := setI2cRegMaster(devInt, READ_C);
148	         v.i2cRegMasterIn.regOp  := '0';  -- Read
149	         v.i2cRegMasterIn.regReq := '1';
150	         v.i2cSelectOut(devInt)  := '1';
151	
152	      end if;
153	
154	      if (i2cRegMasterOut.regAck = '1' and r.i2cRegMasterIn.regReq = '1') then
155	         v.i2cRegMasterIn.regReq := '0';
156	         v.i2cSelectOut          := (others => '0');
157	         axiResp                 := ite(i2cRegMasterOut.regFail = '1', AXI_RESP_SLVERR_C, AXI_RESP_OK_C);
158	         if (r.i2cRegMasterIn.regOp = '1') then
159	            axiSlaveWriteResponse(v.axiWriteSlave, axiResp);
160	         else
161	            v.axiReadSlave.rdata := i2cRegMasterOut.regRdData;
162	            if (i2cRegMasterOut.regFail = '1') then
163	               v.axiReadSlave.rdata := X"000000" & i2cRegMasterOut.regFailCode;
164	            end if;
165	            axiSlaveReadResponse(v.axiReadSlave, axiResp);
166	         end if;
167	
168	      end if;
169	
170	      ----------------------------------------------------------------------------------------------
171	      -- Reset
172	      ----------------------------------------------------------------------------------------------
173	      if (axiRst = '1') then
174	         v := REG_INIT_C;
175	      end if;
176	
177	      rin <= v;
178	
179	      axiReadSlave   <= r.axiReadSlave;
180	      axiWriteSlave  <= r.axiWriteSlave;
181	      i2cSelectOut   <= r.i2cSelectOut;
182	      i2cRegMasterIn <= r.i2cRegMasterIn;
183	
184	   end process comb;
185	
186	   -------------------------------------------------------------------------------------------------
187	   -- Sequential Process
188	   -------------------------------------------------------------------------------------------------
189	   seq : process (axiClk) is
190	   begin
191	      if (rising_edge(axiClk)) then
192	         r <= rin after TPD_G;
193	      end if;
194	   end process seq;
195	
196	end architecture rtl;
197	
