1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: Axi lite interface for a single chip "generic SPI master"
5	--                For multiple chips on single bus connect multiple cores
6	--                to multiple AXI crossbar slaves and use Chip select outputs
7	--                (coreCsb) to multiplex select the addressed outputs (coreSDout and
8	--                coreSclk).
9	--                The coreCsb is active low. And active only if the corresponding
10	--                Axi Crossbar Slave is addressed.
11	--                DATA_SIZE_G - Corresponds to total read or write command size (not just data size).
12	--                              Example: DATA_SIZE_G = 24
13	--                                       1-bit command, 15-bit address word and 8-bit data
14	-------------------------------------------------------------------------------
15	-- This file is part of 'SLAC Firmware Standard Library'.
16	-- It is subject to the license terms in the LICENSE.txt file found in the
17	-- top-level directory of this distribution and at:
18	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
19	-- No part of 'SLAC Firmware Standard Library', including this file,
20	-- may be copied, modified, propagated, or distributed except according to
21	-- the terms contained in the LICENSE.txt file.
22	-------------------------------------------------------------------------------
23	
24	library ieee;
25	use ieee.std_logic_1164.all;
26	use ieee.std_logic_arith.all;
27	use ieee.std_logic_unsigned.all;
28	
29	library unisim;
30	use unisim.vcomponents.all;
31	
32	library surf;
33	use surf.StdRtlPkg.all;
34	use surf.AxiLitePkg.all;
35	
36	entity AxiSpiMaster is
37	   generic (
38	      TPD_G             : time     := 1 ns;
39	      ADDRESS_SIZE_G    : natural  := 15;
40	      DATA_SIZE_G       : natural  := 8;
41	      MODE_G            : string   := "RW";  -- Or "WO" (write only),  "RO" (read only)
42	      SHADOW_EN_G       : boolean  := false;
43	      SHADOW_MEM_TYPE_G : string   := "block";
44	      CPHA_G            : sl       := '0';
45	      CPOL_G            : sl       := '0';
46	      CLK_PERIOD_G      : real     := 6.4E-9;
47	      SPI_SCLK_PERIOD_G : real     := 100.0E-6;
48	      SPI_NUM_CHIPS_G   : positive := 1);
49	   port (
50	      -- AXI-Lite Interface
51	      axiClk         : in  sl;
52	      axiRst         : in  sl;
53	      axiReadMaster  : in  AxiLiteReadMasterType;
54	      axiReadSlave   : out AxiLiteReadSlaveType;
55	      axiWriteMaster : in  AxiLiteWriteMasterType;
56	      axiWriteSlave  : out AxiLiteWriteSlaveType;
57	      -- Copy of the shadow memory (SHADOW_EN_G=true)
58	      -- Same width as ADDRESS_SIZE_G if NUM_CHIPS_G=1
59	      -- Else ADDRESS_SIZE_G+log2(NUM_CHIPS_G)
60	      shadowAddr     : in  slv(ite(SPI_NUM_CHIPS_G = 1, 0, log2(SPI_NUM_CHIPS_G))+ADDRESS_SIZE_G-1 downto 0) := (others => '0');
61	      shadowData     : out slv(DATA_SIZE_G-1 downto 0)                                                       := (others => '0');
62	      -- SPI Interface
63	      coreSclk       : out sl;
64	      coreSDin       : in  sl;
65	      coreSDout      : out sl;
66	      coreCsb        : out sl;  -- coreCsb is for legacy firmware without SPI_NUM_CHIPS_G generic
67	      coreMCsb       : out slv(SPI_NUM_CHIPS_G-1 downto 0));
68	end entity AxiSpiMaster;
69	
70	architecture rtl of AxiSpiMaster is
71	
72	   -- AdcCore Outputs
73	   constant PACKET_SIZE_C          : positive := ite(MODE_G = "RW", 1, 0) + ADDRESS_SIZE_G + DATA_SIZE_G;  -- "1+" For R/W command bit
74	   constant CHIP_BITS_C            : integer  := log2(SPI_NUM_CHIPS_G);
75	   constant SHADOW_MEM_ADDR_SIZE_C : integer  := ite(SPI_NUM_CHIPS_G = 1, 0, log2(SPI_NUM_CHIPS_G))+ADDRESS_SIZE_G;
76	
77	   signal rdData : slv(PACKET_SIZE_C-1 downto 0);
78	   signal rdEn   : sl;
79	
80	   type StateType is (WAIT_AXI_TXN_S, WAIT_CYCLE_S, WAIT_CYCLE_SHADOW_S, WAIT_SPI_TXN_DONE_S, SHADOW_READ_DONE_S);
81	
82	
83	   signal memData : slv(DATA_SIZE_G-1 downto 0)            := (others => '0');
84	   signal memAddr : slv(SHADOW_MEM_ADDR_SIZE_C-1 downto 0) := (others => '0');
85	
86	   -- Registers
87	   type RegType is record
88	      state         : StateType;
89	      axiReadSlave  : AxiLiteReadSlaveType;
90	      axiWriteSlave : AxiLiteWriteSlaveType;
91	      -- Adc Core Inputs
92	      wrData        : slv(PACKET_SIZE_C-1 downto 0);
93	      chipSel       : slv(CHIP_BITS_C-1 downto 0);
94	      wrEn          : sl;
95	   end record RegType;
96	
97	   constant REG_INIT_C : RegType := (
98	      state         => WAIT_AXI_TXN_S,
99	      axiReadSlave  => AXI_LITE_READ_SLAVE_INIT_C,
100	      axiWriteSlave => AXI_LITE_WRITE_SLAVE_INIT_C,
101	      wrData        => (others => '0'),
102	      chipSel       => (others => '0'),
103	      wrEn          => '0');
104	
105	   signal r   : RegType := REG_INIT_C;
106	   signal rin : RegType;
107	   signal csb : slv(SPI_NUM_CHIPS_G-1 downto 0);
108	
109	begin
110	
111	   SHADOW_RAM_GEN : if (SHADOW_EN_G) generate
112	      NO_CHIP_SEL : if (SPI_NUM_CHIPS_G = 1) generate
113	         memAddr <= r.wrData(DATA_SIZE_G+ADDRESS_SIZE_G-1 downto DATA_SIZE_G);
114	      end generate NO_CHIP_SEL;
115	
116	      CHIP_SEL : if (SPI_NUM_CHIPS_G > 1) generate
117	         memAddr <= r.chipSel & r.wrData(DATA_SIZE_G+ADDRESS_SIZE_G-1 downto DATA_SIZE_G);
118	      end generate CHIP_SEL;
119	
120	
121	      U_DualPortRam_1 : entity surf.DualPortRam
122	         generic map (
123	            TPD_G         => TPD_G,
124	            MEMORY_TYPE_G => SHADOW_MEM_TYPE_G,
125	            REG_EN_G      => false,
126	            DATA_WIDTH_G  => DATA_SIZE_G,
127	            ADDR_WIDTH_G  => SHADOW_MEM_ADDR_SIZE_C)
128	         port map (
129	            clka  => axiClk,                            -- [in]
130	            ena   => '1',                               -- [in]
131	            wea   => r.wrEn,                            -- [in]
132	            rsta  => axiRst,                            -- [in]
133	            addra => memAddr,                           -- [in]
134	            dina  => r.wrData(DATA_SIZE_G-1 downto 0),  -- [in]
135	            douta => memData,                           -- [out]
136	            clkb  => axiClk,                            -- [in]
137	            enb   => '1',                               -- [in]
138	            rstb  => axiRst,                            -- [in]
139	            addrb => shadowAddr,                        -- [in]
140	            doutb => shadowData);                       -- [out]
141	
142	   end generate SHADOW_RAM_GEN;
143	
144	
145	   comb : process (axiReadMaster, axiRst, axiWriteMaster, memData, r, rdData,
146	                   rdEn) is
147	      variable v         : RegType;
148	      variable axiStatus : AxiLiteStatusType;
149	   begin
150	      v := r;
151	
152	      axiSlaveWaitTxn(axiWriteMaster, axiReadMaster, v.axiWriteSlave, v.axiReadSlave, axiStatus);
153	
154	      case (r.state) is
155	         when WAIT_AXI_TXN_S =>
156	
157	            if (axiStatus.readEnable = '1') then
158	               if (SHADOW_EN_G) then
159	                  v.state                   := WAIT_CYCLE_SHADOW_S;  -- just go to wait a cycle for memData to update
160	                  v.wrData(PACKET_SIZE_C-1) := '1';  -- indicate axi lite read in WAIT_SPI_TXN_DONE_S checking
161	                  if (ADDRESS_SIZE_G > 0) then
162	                     v.wrData(DATA_SIZE_G+ADDRESS_SIZE_G-1 downto DATA_SIZE_G) := axiReadMaster.araddr(2+ADDRESS_SIZE_G-1 downto 2);  -- setup memAddr
163	                  end if;
164	                  v.chipSel := axiReadMaster.araddr(CHIP_BITS_C+ADDRESS_SIZE_G+1 downto 2+ADDRESS_SIZE_G);
165	               elsif (MODE_G = "WO") then
166	                  axiSlaveReadResponse(v.axiReadSlave, AXI_RESP_DECERR_C);
167	               else
168	                  -- No read bit when mode is read-only
169	                  if (MODE_G /= "RO") then
170	                     v.wrData(PACKET_SIZE_C-1) := '1';
171	                  end if;
172	
173	                  -- Address
174	                  if (ADDRESS_SIZE_G > 0) then
175	                     v.wrData(DATA_SIZE_G+ADDRESS_SIZE_G-1 downto DATA_SIZE_G) := axiReadMaster.araddr(2+ADDRESS_SIZE_G-1 downto 2);
176	                     -- Setting data segment to all 1 allows it to float so that slave side can drive it
177	                     -- in shared sdio configurations
178	                     v.wrData(DATA_SIZE_G-1 downto 0)                          := (others => '1');
179	                  end if;
180	
181	                  -- If there are no address bits, readback will reuse the last wrData when shifting
182	                  v.chipSel := axiReadMaster.araddr(CHIP_BITS_C+ADDRESS_SIZE_G+1 downto 2+ADDRESS_SIZE_G);
183	                  v.wrEn    := '1';
184	                  v.state   := WAIT_CYCLE_S;
185	               end if;
186	
187	            elsif (axiStatus.writeEnable = '1') then
188	               if (MODE_G = "RO") then
189	                  axiSlaveWriteResponse(v.axiWriteSlave, AXI_RESP_DECERR_C);
190	               else
191	                  -- No write bit when mode is write-only
192	                  if (MODE_G /= "WO") then
193	                     v.wrData(PACKET_SIZE_C-1) := '0';
194	                  end if;
195	
196	                  -- Address (make sure that the assigned AXI address in the crossbar is big enough)
197	                  if (ADDRESS_SIZE_G > 0) then
198	                     v.wrData(DATA_SIZE_G+ADDRESS_SIZE_G-1 downto DATA_SIZE_G) := axiWriteMaster.awaddr(2+ADDRESS_SIZE_G-1 downto 2);
199	                  end if;
200	                  -- Data
201	                  v.wrData(DATA_SIZE_G-1 downto 0) := axiWriteMaster.wdata(DATA_SIZE_G-1 downto 0);
202	                  -- Chip select
203	                  v.chipSel                        := axiWriteMaster.awaddr(CHIP_BITS_C+ADDRESS_SIZE_G+1 downto 2+ADDRESS_SIZE_G);
204	                  v.wrEn                           := '1';
205	                  v.state                          := WAIT_CYCLE_S;
206	               end if;
207	            end if;
208	
209	         when WAIT_CYCLE_S =>
210	            -- Wait for rdEn to drop
211	            if (rdEn = '0') then
212	               v.wrEn  := '0';
213	               v.state := WAIT_SPI_TXN_DONE_S;
214	            end if;
215	
216	         when WAIT_CYCLE_SHADOW_S =>
217	            -- wait for memData
218	            v.state := SHADOW_READ_DONE_S;
219	
220	         when WAIT_SPI_TXN_DONE_S =>
221	
222	            if (rdEn = '1') then
223	               v.state := WAIT_AXI_TXN_S;
224	               if (MODE_G = "WO" or (MODE_G = "RW" and r.wrData(PACKET_SIZE_C-1) = '0')) then
225	                  axiSlaveWriteResponse(v.axiWriteSlave);
226	               else
227	                  v.axiReadSlave.rdata(DATA_SIZE_G-1 downto 0) := rdData(DATA_SIZE_G-1 downto 0);
228	                  axiSlaveReadResponse(v.axiReadSlave);
229	               end if;
230	            end if;
231	
232	         when SHADOW_READ_DONE_S =>
233	            v.axiReadSlave.rdata(DATA_SIZE_G-1 downto 0) := memData;
234	            axiSlaveReadResponse(v.axiReadSlave);
235	            v.state                                      := WAIT_AXI_TXN_S;
236	
237	         when others => null;
238	      end case;
239	
240	      -- Check if single access
241	      if (SPI_NUM_CHIPS_G = 1) then
242	         v.chipSel := (others => '0');
243	      end if;
244	
245	      if (axiRst = '1') then
246	         v := REG_INIT_C;
247	      end if;
248	
249	      rin <= v;
250	
251	      axiWriteSlave <= r.axiWriteSlave;
252	      axiReadSlave  <= r.axiReadSlave;
253	
254	   end process comb;
255	
256	   seq : process (axiClk) is
257	   begin
258	      if (rising_edge(axiClk)) then
259	         r <= rin after TPD_G;
260	      end if;
261	   end process seq;
262	
263	   SpiMaster_1 : entity surf.SpiMaster
264	      generic map (
265	         TPD_G             => TPD_G,
266	         NUM_CHIPS_G       => SPI_NUM_CHIPS_G,
267	         DATA_SIZE_G       => PACKET_SIZE_C,
268	         CPHA_G            => CPHA_G,
269	         CPOL_G            => CPOL_G,
270	         CLK_PERIOD_G      => CLK_PERIOD_G,
271	         SPI_SCLK_PERIOD_G => SPI_SCLK_PERIOD_G)
272	      port map (
273	         clk     => axiClk,
274	         sRst    => axiRst,
275	         chipSel => r.chipSel,
276	         wrEn    => r.wrEn,
277	         wrData  => r.wrData,
278	         rdEn    => rdEn,
279	         rdData  => rdData,
280	         spiCsL  => csb,
281	         spiSclk => coreSclk,
282	         spiSdi  => coreSDout,
283	         spiSdo  => coreSDin);
284	
285	   coreCsb  <= csb(0);
286	   coreMCsb <= csb;
287	
288	end architecture rtl;
