17	
18	library ieee;
19	use ieee.std_logic_1164.all;
20	use ieee.numeric_std.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.I2cPkg.all;
25	
26	entity I2cRegMaster is
27	   generic (
28	      TPD_G                : time                      := 1 ns;
29	      OUTPUT_EN_POLARITY_G : integer range 0 to 1      := 0;
30	      FILTER_G             : integer range 2 to 512    := 8;
31	      PRESCALE_G           : integer range 0 to 655535 := 62);
32	   port (
33	      clk    : in  sl;
34	      srst   : in  sl := '0';
35	      arst   : in  sl := '0';
36	      regIn  : in  I2cRegMasterInType;
37	      regOut : out I2cRegMasterOutType;
38	      i2ci   : in  i2c_in_type;
39	      i2co   : out i2c_out_type);
40	end entity I2cRegMaster;
41	
42	architecture rtl of I2cRegMaster is
43	
44	   type StateType is (
45	      WAIT_REQ_S,
46	      ADDR_S,
47	      WRITE_S,
48	      READ_TXN_S,
49	      READ_S,
50	      BUS_ACK_S,
51	      REG_ACK_S);
52	
53	   type RegType is record
54	      state       : StateType;
55	      byteCount   : unsigned(1 downto 0);
56	      regOut      : I2cRegMasterOutType;
57	      i2cMasterIn : I2cMasterInType;
58	   end record RegType;
59	
60	   constant REG_INIT_C : RegType := (
61	      state          => WAIT_REQ_S,
62	      byteCount      => (others => '0'),
63	      regOut         => (
64	         regAck      => '0',
65	         regFail     => '0',
66	         regFailCode => (others => '0'),
67	         regRdData   => (others => '0')),
68	      i2cMasterIn    => (
69	         enable      => '0',
70	         prescale    => (others => '0'),
71	         filter      => (others => '0'),
72	         txnReq      => '0',
73	         stop        => '0',
74	         op          => '0',
75	         busReq      => '0',
76	         addr        => (others => '0'),
77	         tenbit      => '0',
78	         wrValid     => '0',
79	         wrData      => (others => '0'),
80	         rdAck       => '0'));
81	
82	   signal r            : RegType := REG_INIT_C;
83	   signal rin          : RegType;
84	   signal i2cMasterIn  : I2cMasterInType;
85	   signal i2cMasterOut : I2cMasterOutType;
86	
87	   function getIndex (
88	      endianness : sl;
89	      byteCount  : unsigned;
90	      totalBytes : unsigned)
91	      return integer is
92	   begin
93	      if (endianness = '0') then
94	         -- little endian
95	         return to_integer(byteCount)*8;
96	      else
97	         -- big endian
98	         return (to_integer(totalBytes)-to_integer(byteCount))*8;
99	      end if;
100	   end function getIndex;
101	
102	begin
103	
104	   i2cMaster_1 : entity surf.I2cMaster
105	      generic map (
106	         TPD_G                => TPD_G,
107	         OUTPUT_EN_POLARITY_G => OUTPUT_EN_POLARITY_G,
108	         PRESCALE_G           => PRESCALE_G,
109	         FILTER_G             => FILTER_G,
110	         DYNAMIC_FILTER_G     => 0)
111	      port map (
112	         clk          => clk,
113	         srst         => srst,
114	         arst         => arst,
115	         i2cMasterIn  => i2cMasterIn,
116	         i2cMasterOut => i2cMasterOut,
117	         i2ci         => i2ci,
118	         i2co         => i2co);
119	
120	   comb : process (i2cMasterOut, r, regIn, srst) is
121	      variable v            : RegType;
122	      variable addrIndexVar : integer;
123	      variable dataIndexVar : integer;
124	   begin
125	      v := r;
126	
127	      addrIndexVar := getIndex(regIn.endianness, r.byteCount, unsigned(regIn.regAddrSize));
128	      dataIndexVar := getIndex(regIn.endianness, r.byteCount, unsigned(regIn.regDataSize));
129	
130	      v.regOut.regAck  := '0';
131	      v.regOut.regFail := '0';
132	
133	      v.i2cMasterIn.rdAck := '0';
134	
135	      case r.state is
136	         when WAIT_REQ_S =>
137	            v.byteCount := (others => '0');
138	            if (regIn.regReq = '1') then
139	               v.i2cMasterIn.txnReq := '1';
140	               v.i2cMasterIn.op     := '1';
141	               -- Use a repeated start for reads when directed to do so
142	               -- This is done by setting stop to 0 for the regAddr write txn
143	               -- Then the following read txn will be issued with repeated start
144	               v.i2cMasterIn.stop   := ite(regIn.regOp = '0' and regIn.repeatStart = '1', '0', '1');
145	               v.i2cMasterIn.busReq := regIn.busReq;
146	               v.state              := ADDR_S;
147	               if regIn.busReq = '1' then
148	                  v.state := BUS_ACK_S;
149	               elsif (regIn.regAddrSkip = '1') then
150	                  if (regIn.regOp = '1') then
151	                     v.state := WRITE_S;
152	                  else
153	                     v.i2cMasterIn.op := '0';
154	                     v.state          := READ_S;
155	                  end if;
156	               end if;
157	            end if;
158	
159	         when ADDR_S =>
160	            -- When a new register access request is seen,
161	            -- Write the register address out on the bus first
162	            -- One byte at a time, order determined by endianness input
163	            v.i2cMasterIn.wrData  := regIn.regAddr(addrIndexVar+7 downto addrIndexVar);
164	            v.i2cMasterIn.wrValid := '1';
165	            -- Must drop txnReq as last byte is sent if reading
166	            v.i2cMasterIn.txnReq  := not toSl(slv(r.byteCount) = regIn.regAddrSize and regIn.regOp = '0' and regIn.wrDataOnRd = '0');
167	
168	            if (i2cMasterOut.wrAck = '1') then
169	               v.byteCount           := r.byteCount + 1;
170	               v.i2cMasterIn.wrValid := '0';
171	               if (slv(r.byteCount) = regIn.regAddrSize) then
172	                  -- Done sending addr
173	                  v.byteCount := (others => '0');
174	                  if (regIn.regOp = '1' or (regIn.regOp = '0' and regIn.wrDataOnRd = '1')) then
175	                     v.state := WRITE_S;
176	                  else
177	                     v.state := READ_TXN_S;
178	                  end if;
179	               end if;
180	            end if;
181	
182	         when WRITE_S =>
183	            -- Txn started in WAIT_REQ_S still active
184	            -- Put wrData on the bus one byte at a time
185	            v.i2cMasterIn.wrData  := regIn.regWrData(dataIndexVar+7 downto dataIndexVar);
186	            v.i2cMasterIn.wrValid := '1';
187	            v.i2cMasterIn.txnReq  := not toSl(slv(r.byteCount) = regIn.regDataSize);
188	            v.i2cMasterIn.stop    := '1';  -- Send stop when done writing all bytes
189	            if (i2cMasterOut.wrAck = '1') then
190	               v.byteCount           := r.byteCount + 1;
191	               v.i2cMasterIn.wrValid := '0';
192	               if (slv(r.byteCount) = regIn.regDataSize) then  -- could use rxnReq = 0
193	                  if (regIn.regOp = '1') then
194	                     v.state := REG_ACK_S;
195	                  else
196	                     -- Handle wrDataOnRead case
197	                     v.state := READ_TXN_S;
198	                  end if;
199	
200	               end if;
201	            end if;
202	
203	
204	         when READ_TXN_S =>
205	            -- Start new txn to read data bytes
206	            v.i2cMasterIn.txnReq := '1';
207	            v.i2cMasterIn.op     := '0';
208	            v.i2cMasterIn.stop   := '1';  -- i2c stop after all bytes are read
209	            v.byteCount          := (others => '0');
210	            v.state              := READ_S;
211	
212	         when READ_S =>
213	            -- Drop txnReq on last byte
214	            v.i2cMasterIn.txnReq := not toSl(slv(r.byteCount) = regIn.regDataSize);
215	            -- Read data bytes as they arrive
216	            if (i2cMasterOut.rdValid = '1' and r.i2cMasterIn.rdAck = '0') then
217	               v.byteCount                                            := r.byteCount + 1;
218	               v.regOut.regRdData(dataIndexVar+7 downto dataIndexVar) := i2cMasterOut.rdData;
219	               v.i2cMasterIn.rdAck                                    := '1';
220	               if (slv(r.byteCount) = regIn.regDataSize) then
221	                  -- Done
222	                  v.state := REG_ACK_S;
223	               end if;
224	            end if;
225	
226	         when BUS_ACK_S =>
227	            if i2cMasterOut.busAck = '1' then
228	               v.i2cMasterIn.txnReq := '0';
229	               v.state              := REG_ACK_S;
230	            end if;
231	
232	         when REG_ACK_S =>
233	            -- Req done. Ack the req.
234	            -- Might have failed so hold regFail (would be set to 0 otherwise).
235	            v.regOut.regAck  := '1';
236	            v.regOut.regFail := r.regOut.regFail;
237	            if (regIn.regReq = '0') then
238	--          v.regOut.regAck := '0'; Might want this back.
239	               v.state := WAIT_REQ_S;
240	            end if;
241	
242	      end case;
243	
244	      -- Always check for errors and cancel the txn if they happen
245	      if (i2cMasterOut.txnError = '1' and i2cMasterOut.rdValid = '1') then
246	         v.regOut.regFail     := '1';
247	         v.regOut.regFailCode := i2cMasterOut.rdData;
248	         v.i2cMasterIn.txnReq := '0';
249	         v.i2cMasterIn.rdAck  := '1';
250	         v.state              := REG_ACK_S;
251	      end if;
252	
253	      ------------------------------------------------------------------------------------------------
254	      -- Synchronous Reset
255	      ------------------------------------------------------------------------------------------------
256	      if (srst = '1') then
257	         v := REG_INIT_C;
258	      end if;
259	
260	      ------------------------------------------------------------------------------------------------
261	      -- Signal Assignments
262	      ------------------------------------------------------------------------------------------------
263	      -- Update registers
264	      rin <= v;
265	
266	      -- Internal signals
267	      i2cMasterIn.enable   <= '1';
268	      i2cMasterIn.prescale <= slv(to_unsigned(PRESCALE_G, 16));  -- Now unused
269	      i2cMasterIn.filter   <= (others => '0');  -- Not using dynamic filtering
270	      i2cMasterIn.addr     <= regIn.i2cAddr;
271	      i2cMasterIn.tenbit   <= regIn.tenbit;
272	      i2cMasterIn.txnReq   <= r.i2cMasterIn.txnReq;
273	      i2cMasterIn.stop     <= r.i2cMasterIn.stop;
274	      i2cMasterIn.op       <= r.i2cMasterIn.op;
275	      i2cMasterIn.wrValid  <= r.i2cMasterIn.wrValid;
276	      i2cMasterIn.wrData   <= r.i2cMasterIn.wrData;
277	      i2cMasterIn.rdAck    <= r.i2cMasterIn.rdAck;
278	      i2cMasterIn.busReq   <= r.i2cMasterIn.busReq;
279	
280	      -- Outputs
281	      regOut <= r.regOut;
282	
283	   end process comb;
284	
285	   seq : process (arst, clk) is
286	   begin
287	      if (arst = '1') then
288	         r <= REG_INIT_C after TPD_G;
289	      elsif (rising_edge(clk)) then
290	         r <= rin after TPD_G;
291	      end if;
292	   end process seq;
293	
294	end architecture rtl;
