1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: Multiplexes access to a single I2cRegMaster module
5	-- Attached devices may also lock others out in order to execute multiple
6	-- transactions in a row. To do this, lockReq must be set high for the first
7	-- transaction and set low for the last transaction.
8	-------------------------------------------------------------------------------
9	-- This file is part of 'SLAC Firmware Standard Library'.
10	-- It is subject to the license terms in the LICENSE.txt file found in the
11	-- top-level directory of this distribution and at:
12	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
13	-- No part of 'SLAC Firmware Standard Library', including this file,
14	-- may be copied, modified, propagated, or distributed except according to
15	-- the terms contained in the LICENSE.txt file.
16	-------------------------------------------------------------------------------
17	
18	library ieee;
19	use ieee.std_logic_1164.all;
20	use ieee.std_logic_arith.all;
21	use ieee.std_logic_unsigned.all;
22	
23	
24	library surf;
25	use surf.StdRtlPkg.all;
26	use surf.I2cPkg.all;
27	
28	entity I2cRegMasterMux is
29	   generic (
30	      TPD_G        : time                 := 1 ns;
31	      NUM_INPUTS_C : natural range 2 to 8 := 2);
32	   port (
33	      clk       : in  sl;
34	      srst      : in  sl                           := '0';
35	      arst      : in  sl                           := '0';
36	      lockReq   : in  slv(NUM_INPUTS_C-1 downto 0) := (others => '0');
37	      regIn     : in  I2cRegMasterInArray(0 to NUM_INPUTS_C-1);
38	      regOut    : out I2cRegMasterOutArray(0 to NUM_INPUTS_C-1);
39	      masterIn  : out I2cRegMasterInType;
40	      masterOut : in  I2cRegMasterOutType);
41	end entity I2cRegMasterMux;
42	
43	architecture rtl of I2cRegMasterMux is
44	
45	   type RegType is record
46	      locked   : sl;
47	      sel      : slv(log2(NUM_INPUTS_C)-1 downto 0);
48	      regOut   : I2cRegMasterOutArray(0 to NUM_INPUTS_C-1);
49	      masterIn : I2cRegMasterInType;
50	   end record RegType;
51	
52	   constant REG_INIT_C : RegType := (
53	      locked   => '0',
54	      sel      => (others => '0'),
55	      regOut   => (others => I2C_REG_MASTER_OUT_INIT_C),
56	      masterIn => I2C_REG_MASTER_IN_INIT_C);
57	
58	   signal r   : RegType := REG_INIT_C;
59	   signal rin : RegType;
60	
61	begin
62	
63	   comb : process (lockReq, masterOut, r, regIn, srst) is
64	      variable v      : RegType;
65	      variable selInt : integer;
66	   begin
67	      v := r;
68	
69	      selInt := conv_integer(r.sel);
70	
71	      if (r.locked = '0') then
72	         v.sel := r.sel + 1;  -- Increment only if no channel has a lock
73	      else
74	         v.locked := lockReq(selInt);   -- Grant lock if requested
75	      end if;
76	
77	      v.masterIn.regReq := '0';
78	
79	      v.regOut := (others => I2C_REG_MASTER_OUT_INIT_C);
80	
81	      if (regIn(selInt).regReq = '1') then
82	         v.locked         := lockReq(selInt);  -- Grant lock if requested
83	         v.sel            := r.sel;
84	         v.masterIn       := regIn(selInt);
85	         v.regOut(selInt) := masterOut;
86	      end if;
87	
88	      -- If bus is locked and another input tries to access, respond immediately with a fail code
89	      if (r.locked = '1') then
90	         for i in NUM_INPUTS_C-1 downto 0 loop
91	            if (regIn(i).regReq = '1' and r.sel /= i) then
92	               v.regOut(i) := (
93	                  regAck      => '1',
94	                  regFail     => '1',
95	                  regFailCode => "00001111",
96	                  regRdData   => (others => '0'));
97	            end if;
98	         end loop;
99	      end if;
100	
101	      if (srst = '1') then
102	         v := REG_INIT_C;
103	      end if;
104	
105	      rin <= v;
106	
107	      regOut   <= r.regOut;
108	      masterIn <= r.masterIn;
109	
110	   end process comb;
111	
112	   seq : process (arst, clk) is
113	   begin
114	      if (arst = '1') then
115	         r <= REG_INIT_C after TPD_G;
116	      elsif (rising_edge(clk)) then
117	         r <= rin after TPD_G;
118	      end if;
119	   end process seq;
120	
121	end architecture rtl;
122

