library surf;
use surf.StdRtlPkg.all;
use surf.TextUtilPkg.all;
use surf.AxiLitePkg.all;

entity UartAxiLiteMasterFsm is
   generic (
      TPD_G : time := 1 ns);
   port (
      -- Clock and Reset
      axilClk          : in  sl;
      axilRst          : in  sl;
      -- UART TX Streaming Byte Interface
      uartTxValid      : out sl;
      uartTxData       : out slv(7 downto 0);
      uartTxReady      : in  sl;
      -- UART RX Streaming Byte Interface
      uartRxValid      : in  sl;
      uartRxData       : in  slv(7 downto 0);
      uartRxReady      : out sl;
      -- AXI-Lite interface
      mAxilWriteMaster : out AxiLiteWriteMasterType;
      mAxilWriteSlave  : in  AxiLiteWriteSlaveType;
      mAxilReadMaster  : out AxiLiteReadMasterType;
      mAxilReadSlave   : in  AxiLiteReadSlaveType);
end entity UartAxiLiteMasterFsm;

architecture rtl of UartAxiLiteMasterFsm is

   type StateType is (
      WAIT_START_S,
      SPACE_ADDR_S,
      ADDR_SPACE_S,
      WR_DATA_S,
      WAIT_EOL_S,
      AXIL_TXN_S,
      RD_DATA_SPACE_S,
      RD_DATA_S,
      DONE_S);

